const body = $json.body || $json;
const required = ['request_id', 'workflow_type', 'generated_by', 'client', 'brand', 'campaign', 'brief', 'options', 'safety'];
const missing = required.filter((key) => body[key] === undefined || body[key] === null);
const safety = body.safety || {};
const safetyOk = body.workflow_type === 'content_pack'
  && body.owner_approval_required === true
  && safety.no_auto_post === true
  && safety.no_auto_ads === true
  && safety.no_live_connectors === true
  && safety.no_secrets === true
  && safety.owner_approval_required === true;
if (missing.length || !safetyOk) {
  return [{ json: {
    ok: false,
    request_id: body.request_id || null,
    error: {
      code: missing.length ? 'INVALID_CONTRACT' : 'REJECTED_BY_SAFETY',
      message: missing.length ? `Missing required fields: ${missing.join(', ')}` : 'Safety flags rejected this request.'
    },
    status: 'failed',
    owner_approval_required: true,
    safety
  }}];
}
return [{ json: body }];

const request = $json;
const days = Number(request.options?.plan_length_days || 7);
const channel = request.options?.channel || 'Facebook';
const goal = request.options?.goal || 'branding';
const brand = request.brand?.name || 'Brand';
const product = request.brief?.product_focus || request.brand?.hero_product || 'hero product';
const messages = Array.isArray(request.brief?.key_messages) && request.brief.key_messages.length ? request.brief.key_messages : ['Fresh draft angle', 'Owner-approved message', 'Clear customer benefit'];
const pillars = Array.isArray(request.brief?.content_pillars) && request.brief.content_pillars.length ? request.brief.content_pillars : ['Product', 'Offer', 'Trust', 'Lifestyle'];
const items = [];
for (let day = 1; day <= days; day++) {
  const planned = new Date();
  planned.setDate(planned.getDate() + day);
  const message = messages[(day - 1) % messages.length];
  const pillar = pillars[(day - 1) % pillars.length];
  items.push({
    day_number: day,
    planned_date: planned.toISOString().slice(0, 10),
    channel,
    content_type: channel === 'TikTok' ? 'video_script' : 'caption',
    pillar,
    angle: `${goal} / ${pillar}`,
    hook: `${brand}: ${message}`,
    caption: `${product}\n\nGoal: ${goal}.\nDraft angle: ${message}.\nOwner must approve before use.`,
    visual_brief: `Create ${channel} creative for ${brand}. No live publishing.`,
    cta: goal === 'sales' ? 'Message to order.' : 'Follow for the next update.',
    hashtags: `#${brand.replace(/\s+/g, '')} #TheCoreAgency #${channel}`,
    generated_by: 'n8n-ai-provider-placeholder',
    workflow_type: 'content_pack',
    status: 'pending_approval',
    owner_approval_required: true
  });
}
return [{ json: {
  ok: true,
  request_id: request.request_id,
  workflow_type: 'content_pack',
  generated_by: 'n8n-ai-provider-placeholder',
  owner_approval_required: true,
  status: 'pending_approval',
  job: {
    external_execution_id: $execution.id,
    item_count: items.length
  },
  items,
  safety: request.safety
}}];
